import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from 'react-router-dom';

// COMPONENTS
import Navbar from './Navbar';
import LoginForm from './LoginForm';
import LandingPage from './LandingPage'; // 1. Restoring the Landing Page

// PAGES
import Dashboard from './app_pages/Dashboard';
import Uploads from './app_pages/Uploads';
import Compare from './app_pages/Compare';

const Placeholder = ({ title }) => (
    <div style={{ padding: '50px', textAlign: 'center', color: '#888' }}>
        <h1>{title}</h1>
        <p>🚧 Module under construction</p>
    </div>
);

// Layout Component to fix the "Cut Off" issue
const AppLayout = ({ children, onLogout }) => (
  <div style={{ display: 'flex', minHeight: '100vh', backgroundColor: '#f5f7fa' }}>
    <Navbar onLogout={onLogout} />
    {/* 2. Fix Layout: Ensure content starts AFTER the sidebar */}
    <div style={{ flex: 1, marginLeft: '250px', width: 'calc(100% - 250px)', overflowX: 'hidden' }}>
      {children}
    </div>
  </div>
);

const App = () => {
  const [userId, setUserId] = useState(localStorage.getItem('userId'));

  const handleLogin = (id) => {
    localStorage.setItem('userId', id);
    setUserId(id);
  };

  const handleLogout = () => {
    localStorage.removeItem('userId');
    setUserId(null);
  };

  return (
    <Router>
      <Routes>
        {/* --- PUBLIC ROUTES (No Sidebar) --- */}
        <Route path="/" element={!userId ? <LandingPage /> : <Navigate to="/dashboard" />} />

        <Route path="/login" element={
            !userId ? <LoginForm isSignup={false} onLogin={handleLogin} /> : <Navigate to="/dashboard" />
        } />

        <Route path="/signup" element={
            !userId ? <LoginForm isSignup={true} onLogin={handleLogin} /> : <Navigate to="/dashboard" />
        } />

        {/* --- PRIVATE ROUTES (With Sidebar) --- */}
        {/* We use a "Catch-All" to protect all these routes */}
        <Route path="/*" element={
          userId ? (
            <AppLayout onLogout={handleLogout}>
              <Routes>
                <Route path="/dashboard" element={<Dashboard />} />
                <Route path="/uploads" element={<Uploads />} />
                <Route path="/compare" element={<Compare />} />

                {/* Modules Coming Soon */}
                <Route path="/emissions" element={<Placeholder title="Emissions Breakdown" />} />
                <Route path="/sinks" element={<Placeholder title="Sinks & Gap" />} />
                <Route path="/pathways" element={<Placeholder title="Pathways & Scenarios" />} />
                <Route path="/reports" element={<Placeholder title="Reports" />} />
                <Route path="/profile" element={<Placeholder title="Account" />} />

                {/* Redirect unknowns to dashboard */}
                <Route path="*" element={<Navigate to="/dashboard" />} />
              </Routes>
            </AppLayout>
          ) : (
            <Navigate to="/" />
          )
        } />
      </Routes>
    </Router>
  );
};

export default App;
